using System.Collections;
using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Zona do mundo que define a música de fundo (BGM) e/ou som ambiente (BGS)
/// para a área coberta pelo seu Collider2D (deve ter "Is Trigger" activo).
///
/// Quando o player entra na zona, ela regista-se em AudioManager; quando sai,
/// é removida. O AudioManager escolhe, para cada canal (BGM/BGS)
/// separadamente, a zona activa de maior "priority" que define um clip
/// nesse canal.
///
/// Isto permite, por exemplo:
/// - Uma zona grande cobrindo uma área inteira, com bgmClip = música da área
///   e priority = 0.
/// - Uma zona pequena dentro dela (ex: dentro de uma caverna), com
///   bgsClip = eco/gotas de água, bgmClip vazio e priority = 1 — ao entrar,
///   só o som ambiente muda; a música da área continua a tocar. Ao sair,
///   o som ambiente volta ao da zona maior (ou silencia, se a zona maior
///   também não definir BGS).
/// </summary>
[RequireComponent(typeof(Collider2D))]
public class MusicZone : MonoBehaviour
{
    [Header("Identidade")]
    [Tooltip("Apenas para identificação no Inspector/depuração.")]
    public string zoneId;

    [Header("Áudio")]
    [Tooltip("Música de fundo desta zona. Deixa vazio para não alterar o BGM ao entrar nesta zona.")]
    public AudioClip bgmClip;

    [Tooltip("Som ambiente desta zona. Deixa vazio para não alterar o BGS ao entrar nesta zona.")]
    public AudioClip bgsClip;

    public bool loop = true;

    [Header("Transição")]
    [Tooltip("Duração do crossfade ao entrar nesta zona (ou ao sair, se for a zona activa para esse canal).")]
    public float fadeTime = 1.5f;

    [Tooltip("Zonas com prioridade maior ganham a outras zonas sobrepostas (ex: uma sala dentro de uma área maior).")]
    public int priority;

    [Header("Condições (Etapa 8)")]
    [Tooltip("Esta zona só conta para ApplyActiveZones (BGM/BGS) enquanto TODAS estas condições forem verdadeiras. Lista vazia = sempre activa (comportamento anterior). Útil para, por ex., só tocar esta música quando uma variável global/local tiver um certo valor, ou quando um NPC (por ID, ver \"Npc Id\") estiver num certo estado ou visível — ver VariableConditions e NpcStateConditions. Estas condições são avaliadas sem um NPC associado (Evaluate(null)), por isso usa os campos de ID para referenciar NPCs.")]
    [SerializeReference] private List<NpcCondition> conditions = new List<NpcCondition>();

    [Tooltip("Intervalo (segundos) entre verificações das condições acima enquanto o player estiver dentro da zona. Só é relevante se a lista de condições não estiver vazia.")]
    [SerializeField] private float conditionCheckInterval = 0.5f;

    private Coroutine _conditionRoutine;

    private void Reset()
    {
        var col = GetComponent<Collider2D>();
        if (col != null) col.isTrigger = true;
    }

    private void OnTriggerEnter2D(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;

        AudioManager.Instance?.RegisterZone(this);

        if (conditions != null && conditions.Count > 0 && _conditionRoutine == null)
            _conditionRoutine = StartCoroutine(MonitorConditions());
    }

    private void OnTriggerExit2D(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;

        AudioManager.Instance?.UnregisterZone(this);
        StopMonitoringConditions();
    }

    private void OnDisable()
    {
        // Garante que a zona não fica "presa" como activa se for desactivada
        // enquanto o player está dentro dela.
        AudioManager.Instance?.UnregisterZone(this);
        StopMonitoringConditions();
    }

    /// <summary>
    /// true se todas as "conditions" estiverem cumpridas (ou se a lista
    /// estiver vazia). Chamado por AudioManager.ApplyActiveZones para decidir
    /// se esta zona conta para a escolha de BGM/BGS.
    /// </summary>
    public bool ConditionsMet()
    {
        if (conditions == null) return true;

        for (int i = 0; i < conditions.Count; i++)
        {
            var condition = conditions[i];
            if (condition == null) continue;
            if (!condition.Evaluate(null)) return false;
        }

        return true;
    }

    private void StopMonitoringConditions()
    {
        if (_conditionRoutine == null) return;
        StopCoroutine(_conditionRoutine);
        _conditionRoutine = null;
    }

    /// <summary>
    /// Enquanto o player estiver na zona, reavalia "conditions"
    /// periodicamente; se o resultado mudar (ex: uma variável global mudou),
    /// pede ao AudioManager para reescolher as zonas activas de BGM/BGS.
    /// </summary>
    private IEnumerator MonitorConditions()
    {
        bool lastResult = ConditionsMet();

        while (true)
        {
            yield return new WaitForSeconds(conditionCheckInterval);

            bool result = ConditionsMet();
            if (result != lastResult)
            {
                lastResult = result;
                AudioManager.Instance?.RefreshActiveZones();
            }
        }
    }
}
